var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"실험한 내용들을 아주 상세하게 기록해 놨어.","JPN":"実験の内容がとても詳しく記録されていたわ。","ENG":"Ludwig kept detailed records of his experiments.","TWN":"我已經詳細記錄了實驗內容。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"정리한 내용들만 간추려서 이야기해 줄게.","JPN":"まとめた内容をざっと話すわね。","ENG":"I'll summarize the key findings for you.","TWN":"我只會簡要地告訴你整理好的內容。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"루드윅은 감염자의 핏속에 들어 있는 인자가 붉은 달 현상을 유도한다는 사실을 깨달았어.","JPN":"ルードヴィヒは、感染者の血液に含まれているファクターが赤い月現象を誘導するという事実を発見した。","ENG":"He discovered that the factor within an afflicted's blood triggers the Red Moon phenomenon.","TWN":"路易發現感染者血液中的因子會引發紅月現象。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그 가설을 증명하기 위해 멍멍이를 직접 실험대 위에 올리려고 한 거고.","JPN":"その仮説を証明するために、ワンちゃんで直接実験しようとした。","ENG":"And to prove his theory... he was planning to put you on the test table, Puppy.","TWN":"為了證明那個假設，他打算把狗狗直接放到實驗台上。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 그 한계는 명확했죠.","JPN":"でも、そこには明確な限界が存在しました。","ENG":"But his limits were obvious.","TWN":"但那終究是有限的。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"결국 침식 쐐기의 역할을 하는 매개만 부수면 끝나는 일이었으니까요.","JPN":"結局、侵食楔の役割をする媒介さえ壊せば済む話でしたから。","ENG":"In the end, all it took was breaking the medium that acted as a Corrupted Wedge.","TWN":"畢竟只要破壞代替侵蝕釘作用的媒介就行了。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"유의미한 결론을 낸 것도 사실이야.","JPN":"でも有意義な結論を出したのも事実よ。","ENG":"Still, his conclusions were meaningful.","TWN":"得出了有意義的結論也是事實。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"이상 침식 현상을 일으킨 존재가 있다는 것을 알아냈으니까.","JPN":"異常侵食現象を起こした存在がいる、ということがわかったのだから。","ENG":"Through you, he confirmed that some entity triggered the Aberrant Counterside Effect.","TWN":"因為發現了引起異常侵蝕現象的存在。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"존재만으로도…… 영향을 주는…….","JPN":"存在だけで……影響を及ぼす……","ENG":"An entity that... influences just by existing...","TWN":"僅僅是存在……就能產生影響……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래.","JPN":"ええ。","ENG":"Exactly.","TWN":"好吧。"},"stage":{"bg":"MS_1203","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"세계에 넘어오는 것만으로도 영향을 미치는 존재들이지.","JPN":"この世界に現れるだけで、多大な影響を与える存在たち。","ENG":"There are beings that influence the world simply by crossing over.","TWN":"僅僅是來到這個世界就能產生影響的存在。"},"stage":{"bg":"MS_1203","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"로터스에 내렸던 눈이라던가…… 그런 것들 말이야.","JPN":"ロータスに降った雪とか……そういうものよ。","ENG":"Like the snowfall over Lotus... and other such anomalies.","TWN":"比如說洛德斯下的雪……之類的。"},"stage":{"bg":"MS_1203","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 이상 침식 현상도 그런 존재들에 의해 일어난 거예요?","JPN":"じゃあ、異常侵食現象もそういう存在によって起こったんですか？","ENG":"So the Aberrant Counterside Effect was caused by one of these beings?","TWN":"那麼異常侵蝕現象也是由那些存在引起的嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうね。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"추측에 불과하지만, 부력의 원리와 비슷할지도 모르지.","JPN":"これはあくまでも推測だけど、浮力に近い原理なのかもしれないわ。","ENG":"Think of it as a side effect.","TWN":"雖然只是猜測，但可能和浮力的原理相似。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"부력이요?","JPN":"浮力、ですか？","ENG":"Side effect...?","TWN":"浮力嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"물이 가득 찬 욕조에 들어가면 질량만큼의 물이 넘치는 것과 같은 원리야.","JPN":"お湯をいっぱい張った湯舟に入ると、質量分のお湯が溢れるのと同じ原理ね。","ENG":"It's like when you step into a full bathtub, and the water spills over.","TWN":"就像進入裝滿水的浴缸時，會溢出與品質相同的水一樣的原理。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"세계에 영향을 미치는 존재가 우리 세상에 들어온 만큼, 그만큼의 침식파가 흘러넘치게 되는 거지.","JPN":"世界に影響を与える存在がこっちの世界に入って来たってことは、その分侵食波が溢れるってことなの。","ENG":"When a being that affects reality enters this world, it displaces enough energy to unleash Corruption rays.","TWN":"對這個世界產生影響的存在進入我們的世界，侵蝕波就會跟著氾濫起來。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"마왕이 일으켰다기엔 범위가 집약적이고, 일개 침식체가 일으켰다기엔 지나치게 광범위해.","JPN":"魔王の仕業とするには範囲が集約的すぎるし、ただの侵食体の仕業とするには範囲が広すぎる。","ENG":"If this were caused by a Demon Lord, the effect would be too localized. But it's far too widespread to be the work of a C.O.","TWN":"說是魔王引起的，範圍又太集中；說是某個侵蝕體引起的，又過於廣泛。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"무슨 뜻인지 알지?","JPN":"どういう意味か、わかるわよね？","ENG":"You understand what that means, right?","TWN":"知道什麼意思嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……사도.","JPN":"……使徒。","ENG":"...An Apostle.","TWN":"……使徒。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"사도가 이 세계에 강림했을 때의 반동이로군요.","JPN":"使徒がこの世界に降臨した時の反動ですね。","ENG":"It was caused by an Apostle descending into this world.","TWN":"這是使徒降臨這個世界時的反作用力。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"역시 멍멍이야. 돈을 벌려면 머리도 좋아야 한다는 걸 잘 보여주고 있어.","JPN":"さすがワンちゃん。お金儲けには頭の切れが必要ってことを存分に証明してるわね。","ENG":"That's right, Puppy. You show that making money requires brains, too.","TWN":"果然是狗狗。為了賺錢，頭腦也要聰明，這一點你表現得很好。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"자~ 에그타르트 하나~","JPN":"はい、エッグタルト1個～","ENG":"Here, have an egg tart.","TWN":"來～賞你個個蛋撻～"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그러면 저나 카타리나는…….","JPN":"じゃあ、私やカタリナは……","ENG":"Then... does that mean Katharina and I–","TWN":"那樣的話，我和卡特莉娜……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"잠들어 있던 환상종의 인자가 발현한 거야.","JPN":"眠っていた幻想種のファクターが発現したの。","ENG":"The Bygone Factor that lay dormant was awakened.","TWN":"沉睡中的夢幻品種因子顯現出來了。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};